package com.chaobo.scm.supplier.infrastructure.persistence.returning;
import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.returning.*;import com.chaobo.scm.supplier.domain.returning.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierReturnAdapter implements SupplierReturnRepository,SupplierReturnReadModelPort{private final SupplierReturnMapper mapper;public MyBatisSupplierReturnAdapter(SupplierReturnMapper mapper){this.mapper=mapper;}public Optional<SupplierReturnAggregate> findById(long id){var h=mapper.find(id);return h==null?Optional.empty():Optional.of(aggregate(h));}public void save(SupplierReturnAggregate a,long operator){var h=header(a);if(mapper.find(a.id())==null){mapper.insert(h,operator);for(var l:a.lines())mapper.insertLine(line(a.id(),l));}else{if(mapper.update(h,a.version()-1,operator)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"退供单已被更新");for(var l:a.lines())mapper.updateLine(line(a.id(),l));}}public Optional<SupplierReturnView> detail(long id){var h=mapper.find(id);return h==null?Optional.empty():Optional.of(view(h));}public PageResult<SupplierReturnView> page(Long supplierId,Integer status,int page,int size){return new PageResult<>(page,size,mapper.count(supplierId,status),mapper.page(supplierId,status,(page-1)*size,size).stream().map(this::view).toList());}private SupplierReturnAggregate aggregate(SupplierReturnMapper.Header h){return SupplierReturnAggregate.rehydrate(h.id(),h.no(),h.supplierId(),h.warehouseId(),h.qualityIssueId(),h.reason(),mapper.lines(h.id()).stream().map(l->new SupplierReturnLine(l.id(),l.skuCode(),l.batchNo(),l.inventoryStatus(),l.requestedQty(),l.lockedQty(),l.outboundQty(),l.signedQty())).toList(),h.status(),h.inventoryLockNo(),h.supplierConfirmedAt(),h.outboundNo(),h.shipmentId(),h.waybillNo(),h.carrierCode(),h.settlementCompleted(),h.settlementRef(),h.offsetAmount(),h.claimAmount(),h.exceptionReason(),h.version());}private SupplierReturnMapper.Header header(SupplierReturnAggregate a){return new SupplierReturnMapper.Header(a.id(),a.no(),a.supplierId(),a.warehouseId(),a.qualityIssueId(),a.reason(),a.status().code(),a.inventoryLockNo(),a.supplierConfirmedAt(),a.outboundNo(),a.shipmentId(),a.waybillNo(),a.carrierCode(),a.settlementCompleted(),a.settlementRef(),a.offsetAmount(),a.claimAmount(),a.exceptionReason(),a.version());}private SupplierReturnMapper.Line line(long returnId,SupplierReturnLine l){return new SupplierReturnMapper.Line(l.id(),returnId,l.skuCode(),l.batchNo(),l.inventoryStatus(),l.requestedQty(),l.lockedQty(),l.outboundQty(),l.signedQty());}private SupplierReturnView view(SupplierReturnMapper.Header h){var s=SupplierReturnStatus.fromCode(h.status());return new SupplierReturnView(h.id(),h.no(),h.supplierId(),h.warehouseId(),h.qualityIssueId(),h.reason(),s.code(),s.label(),h.inventoryLockNo(),h.supplierConfirmedAt(),h.outboundNo(),h.shipmentId(),h.waybillNo(),h.carrierCode(),h.settlementCompleted(),h.settlementRef(),h.offsetAmount(),h.claimAmount(),h.exceptionReason(),h.version(),mapper.lines(h.id()).stream().map(l->new SupplierReturnView.Line(l.id(),l.skuCode(),l.batchNo(),l.inventoryStatus(),l.requestedQty(),l.lockedQty(),l.outboundQty(),l.signedQty())).toList());}}
